import { I_CommentScene } from '@containers/Home/types';
import { Button } from 'antd';
import dynamic from 'next/dynamic';
import { memo, useCallback } from 'react';
import { CommentScenePopoverWrapper } from './styled';

const CommentBox = dynamic(() => import('./CommentBox'));
const CommentSceneItem = dynamic(() => import('./CommentSceneItem'));

interface Props {
  onClose: () => void;
  commentSceneSelected: I_CommentScene;
  onCreateCommentScene: (data) => void;
  onUpdateCommentScene: (data) => void;
  onDeleteCommentScene: (data, isClosePopover?: boolean) => void;
}

const Popover = memo(
  ({
    onClose,
    commentSceneSelected,
    onCreateCommentScene,
    onUpdateCommentScene,
    onDeleteCommentScene,
  }: Props) => {
    const _onCreateCommentScene = useCallback(
      message => {
        onCreateCommentScene({
          message,
          parent: commentSceneSelected.id,
          scene_id: commentSceneSelected.scene,
          ath: 0,
          atv: 0,
        });
      },
      [commentSceneSelected, onCreateCommentScene],
    );

    const _onDeleteParentCommentScene = useCallback(
      data => {
        onDeleteCommentScene(data, true);
      },
      [onDeleteCommentScene],
    );

    return (
      <CommentScenePopoverWrapper>
        <div className="--close" onClick={onClose}>
          <i aria-hidden className="fas fa-times" />
        </div>
        <div className="--parent">
          <CommentSceneItem
            onUpdate={onUpdateCommentScene}
            commentScene={commentSceneSelected}
            onDelete={_onDeleteParentCommentScene}
          >
            {!!commentSceneSelected.isOwnerTour && (
              <div className="--action">
                <Button
                  disabled={!!commentSceneSelected.isResolved}
                  size="small"
                  onClick={onUpdateCommentScene.bind(this, {
                    ...commentSceneSelected,
                    ath: undefined,
                    atv: undefined,
                    message: undefined,
                    scene_id: commentSceneSelected.scene,
                    isResolved: true,
                  })}
                >
                  <i aria-hidden className="fal fa-check" />
                  <span>
                    {commentSceneSelected.isResolved
                      ? 'Resolved'
                      : 'Mark as Resolved'}
                  </span>
                </Button>
              </div>
            )}
          </CommentSceneItem>
        </div>
        {!!commentSceneSelected.children?.length && (
          <div className="--children hide-scrollbar">
            {commentSceneSelected.children?.map(item => (
              <CommentSceneItem
                key={item.id}
                layout="children"
                commentScene={item}
                onUpdate={onUpdateCommentScene}
                onDelete={onDeleteCommentScene}
              />
            ))}
          </div>
        )}
        <div className="--add-new">
          <CommentBox
            initValue=""
            isShowBtnReset
            onCancel={() => {}}
            isShowBtnCancel={false}
            onSubmit={_onCreateCommentScene}
          />
        </div>
      </CommentScenePopoverWrapper>
    );
  },
);

export default Popover;
